#include <stdio.h>
#include <math.h>

int isPrime(int n){
    if(n<=1) return 0;
    for(int i=2;i*i<=n;++i) if(n%i==0) return 0;
    return 1;
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int L,R; scanf("%d %d",&L,&R);
        int first=1;
        for(int i=L;i<=R;++i){
            if(isPrime(i)){
                if(!first) printf(" ");
                printf("%d",i);
                first=0;
            }
        }
        printf("\n");
    }
    return 0;
}

